@* Displays the current theme in the header — works in static SSR context *@

<span class="badge" style="background-color: @(Theme?.AccentColor ?? "#0d6efd");">
    @(Theme?.Mode.ToString() ?? "Light") Mode
</span>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }
}

@* Quick theme toggle — usable from any interactive component *@

@inject CascadingValueSource<ThemeInfo> ThemeSource

<button class="btn btn-sm btn-outline-secondary" @onclick="ToggleTheme">
    @(Theme?.Mode switch
    {
        ThemeMode.Dark => "🌙",
        ThemeMode.System => "💻",
        _ => "☀️"
    })
</button>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private async Task ToggleTheme()
    {
        var current = Theme ?? new ThemeInfo();
        var nextMode = current.Mode switch
        {
            ThemeMode.Light => ThemeMode.Dark,
            ThemeMode.Dark => ThemeMode.System,
            _ => ThemeMode.Light
        };
        await ThemeSource.NotifyChangedAsync(current with { Mode = nextMode });
    }
}

