    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="mb-3">
            <label class="form-label">Mode</label>
            <select class="form-select" value="@selectedMode" @onchange="OnModeChanged">
                @foreach (var mode in Enum.GetValues<ThemeMode>())
                {
                    <option value="@mode">@mode</option>
                }
            </select>
        </div>

        <div class="mb-3">
            <label class="form-label">Accent Color</label>
            <input type="color" class="form-control form-control-color"
                   value="@accentColor" @onchange="OnAccentChanged" />
        </div>

        <div class="mt-3">
            <span>Preview: </span>
            <span class="badge" style="background-color: @accentColor;">
                @selectedMode Mode
            </span>
        </div>
    </div>
</div>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private ThemeMode selectedMode;
    private string accentColor = "#0d6efd";

    protected override void OnParametersSet()
    {
        if (Theme is not null)
        {
            selectedMode = Theme.Mode;
            accentColor = Theme.AccentColor;
        }
    }

    private async Task OnModeChanged(ChangeEventArgs e)
    {
        selectedMode = Enum.Parse<ThemeMode>(e.Value?.ToString() ?? "Light");
        await ApplyChanges();
    }

