    {
        accentColor = e.Value?.ToString() ?? "#0d6efd";
        await ApplyChanges();
    }

    private async Task ApplyChanges()
    {
        await ThemeSource.NotifyChangedAsync(new ThemeInfo(selectedMode, accentColor));
    }
}

